function sanitizeLegacyMarkdown(text) {
  if (typeof text !== 'string') return text;

  // 1. Normalize GitHub-style bold **X** -> *X* (legacy Markdown uses single asterisk)
  text = text.replace(/\*\*([^\n*]+)\*\*/g, '*$1*');

  // 2. Identify valid paired *bold* ranges (simple, non-nested)
  const protect = (src, ch) => {
    const ranges = [];
    const re = new RegExp('\\' + ch + '([^\\n\\' + ch + ']+)\\' + ch, 'g');
    let m;
    while ((m = re.exec(src)) !== null) {
      ranges.push([m.index, m.index + m[0].length]);
    }
    let out = '';
    for (let i = 0; i < src.length; i++) {
      const c = src[i];
      if (c === ch) {
        const inside = ranges.some(([a, b]) => i >= a && i < b);
        out += inside ? c : '\\' + c;
      } else {
        out += c;
      }
    }
    return out;
  };

  text = protect(text, '*');
  text = protect(text, '_');

  return text;
}

const raw = $json.output;
const text = sanitizeLegacyMarkdown(raw);

const MAX = 4000;
const chunks = [];
let remaining = text;
while (remaining.length > MAX) {
  let cut = remaining.lastIndexOf('\n', MAX);
  if (cut <= 0) cut = MAX;
  chunks.push(remaining.slice(0, cut));
  remaining = remaining.slice(cut).trimStart();
}
chunks.push(remaining);

return chunks.map(c => ({ json: { ...($json), text: c } }));

const projects = $json.projects || [];

if (!projects.length) {
  return [{ json: {
    text: 'У тебя пока нет проектов.\n\nСоздай первый: "создай проект про [тему]"'
  }}];
}

const statusEmoji = { active: "✅", paused: "⏸", archived: "📦" };

let msg = "📁 Твои проекты:\n\n";
for (const p of projects) {
  msg += `${statusEmoji[p.status] || "❓"} ${p.title}\n`;
  if (p.description) msg += `   ${p.description}\n`;
  if (p.keywords?.length) msg += `   🏷 ${p.keywords.join(", ")}\n`;
  msg += "\n";
}

return [{ json: { text: msg.trim() } }];

const ideas = $json.ideas || [];

if (!ideas.length) {
  return [{ json: {
    text: 'У тебя пока нет идей.\n\nДобавь первую: "добавь идею про [тему] в проект [название]"'
  }}];
}

const statusEmoji = { active: "✅", paused: "⏸", done: "✔️", dropped: "❌" };

let msg = "💡 Твои идеи:\n\n";
for (const i of ideas) {
  msg += `${statusEmoji[i.status] || "❓"} ${i.title}\n`;
  if (i.description) msg += `   ${i.description}\n`;
  if (i.keywords?.length) msg += `   🏷 ${i.keywords.join(", ")}\n`;
  msg += "\n";
}

return [{ json: { text: msg.trim() } }];

const trigger = $('Telegram Trigger').first()?.json || {};
const message = trigger.message || {};
const userText = message.text || message.caption || '';

let userId = null;
try { userId = $('Merge').first()?.json?.user_id ?? null; } catch (_) {}
const chatId = message.chat?.id ?? null;

const agentItem = $('AI Agent').first()?.json || {};
let botReply = '';
if (typeof agentItem.output === 'string') {
  botReply = agentItem.output;
} else if (typeof agentItem.text === 'string') {
  botReply = agentItem.text;
} else {
  botReply = JSON.stringify(agentItem);
}

const MAX_TOOL_OUT = 20000;
function truncate(v) {
  if (v == null) return v;
  const s = typeof v === 'string' ? v : JSON.stringify(v);
  return s.length > MAX_TOOL_OUT ? s.slice(0, MAX_TOOL_OUT) + `… [truncated ${s.length - MAX_TOOL_OUT} chars]` : s;
}

let toolsCalled = [];
try {
  const steps = agentItem.intermediateSteps || agentItem.intermediate_steps || [];
  toolsCalled = steps.map(s => ({
    tool: s.action?.tool ?? s.tool ?? null,
    input: s.action?.toolInput ?? s.toolInput ?? null,
    output: truncate(s.observation ?? s.result ?? null),
  })).filter(t => t.tool);
} catch (_) {}

return [{
  json: {
    success: true,
    user_id: userId,
    telegram_chat_id: chatId,
    user_message: userText,
    bot_reply: botReply,
    tools_called: toolsCalled,
  }
}];
